// Get all input items
const items = $input.all();

// Process each item
return items.map(item => {
  // Try multiple phone fields from apollo_leads
  const phoneNumber = item.json.work_direct_phone || item.json.mobile_phone || item.json.home_phone || item.json.corporate_phone || item.json.other_phone || item.json.company_phone || '';

  // Convert to string and remove all non-digit characters
  let cleanNumber = String(phoneNumber).replace(/\D/g, '');

  // Handle different cases
  let standardizedNumber;

  if (cleanNumber.length === 10) {
    // Perfect - just 10 digits (US)
    standardizedNumber = cleanNumber;
  } else if (cleanNumber.length === 11 && cleanNumber.startsWith('1')) {
    // US number with country code +1
    standardizedNumber = cleanNumber.slice(1);
  } else if (cleanNumber.length >= 10 && cleanNumber.length <= 15) {
    // International number - keep as is
    standardizedNumber = cleanNumber;
  } else if (cleanNumber.length === 0) {
    standardizedNumber = 'no_phone';
  } else {
    // Wrong format
    standardizedNumber = 'incorrect format';
  }

  // Build lead context for VAPI
  const leadContext = {
    lead_id: item.json.id,
    first_name: item.json.first_name || '',
    last_name: item.json.last_name || '',
    full_name: `${item.json.first_name || ''} ${item.json.last_name || ''}`.trim(),
    title: item.json.title || '',
    company_name: item.json.company_name || '',
    email: item.json.email || '',
    industry: item.json.industry || '',
    num_employees: item.json.num_employees || '',
    seniority: item.json.seniority || '',
    departments: item.json.departments || '',
    city: item.json.city || '',
    state: item.json.state || '',
    country: item.json.country || '',
    person_linkedin_url: item.json.person_linkedin_url || '',
    website: item.json.website || '',
    annual_revenue: item.json.annual_revenue || '',
    technologies: item.json.technologies || '',
    keywords: item.json.keywords || '',
    primary_intent_topic: item.json.primary_intent_topic || '',
    primary_intent_score: item.json.primary_intent_score || '',
    phone_number: standardizedNumber,
    phone_source: item.json.work_direct_phone ? 'work_direct' : (item.json.mobile_phone ? 'mobile' : (item.json.home_phone ? 'home' : (item.json.corporate_phone ? 'corporate' : 'other'))),
    call_attempts: (item.json.call_attempts || 0) + 1
  };

  return {
    json: leadContext
  };
});

// Extract structured outputs from VAPI call
const item = $input.first();
const json = item.json;

// Get structured outputs from VAPI artifact
const structuredOutputs = json.artifact?.structuredOutputs || {};

// Map the VAPI structured output IDs to our fields
// IMPORTANT: Replace these UUIDs with YOUR actual VAPI structured output IDs
const outputs = Object.values(structuredOutputs);

// Try to find outputs by their names/types or use the values directly
let intention = '';
let budget = '';
let urgency = '';
let motivation = '';
let serviceInterest = '';
let rightPerson = false;
let pastExperience = '';
let callSummary = '';

// If using named structured outputs, map them
for (const [key, value] of Object.entries(structuredOutputs)) {
  const result = value.result || value;
  const name = (value.name || key).toLowerCase();

  if (name.includes('intent') || name.includes('intencion') || name.includes('intención')) {
    intention = result;
  } else if (name.includes('budget') || name.includes('presupuesto')) {
    budget = result;
  } else if (name.includes('urgency') || name.includes('urgencia')) {
    urgency = result;
  } else if (name.includes('motivation') || name.includes('motivacion') || name.includes('motivación')) {
    motivation = result;
  } else if (name.includes('service') || name.includes('servicio') || name.includes('interest') || name.includes('interés')) {
    serviceInterest = result;
  } else if (name.includes('right_person') || name.includes('persona') || name.includes('decision')) {
    rightPerson = result === 'true' || result === 'yes' || result === 'sí' || result === true;
  } else if (name.includes('experience') || name.includes('experiencia')) {
    pastExperience = result;
  } else if (name.includes('summary') || name.includes('resumen')) {
    callSummary = result;
  }
}

// Get transcript
const transcript = json.artifact?.transcript || json.transcript || '';
const transcriptText = typeof transcript === 'string' ? transcript : 
  (Array.isArray(transcript) ? transcript.map(t => `${t.role}: ${t.message}`).join('\n') : JSON.stringify(transcript));

// If no summary from structured outputs, try to get from analysis
if (!callSummary && json.analysis?.summary) {
  callSummary = json.analysis.summary;
}

return [{
  json: {
    lead_id: $('Standardize & Enrich Data').item.json.lead_id,
    call_intention: intention,
    call_budget: budget,
    call_urgency: urgency,
    call_motivation: motivation,
    call_service_interest: serviceInterest,
    call_right_person: rightPerson,
    call_past_experience: pastExperience,
    call_summary: callSummary,
    call_transcript: transcriptText,
    vapi_call_id: json.id,
    call_ended_reason: json.endedReason,
    call_duration_seconds: json.costBreakdown?.duration || 0,
    // Keep original VAPI data for reference
    raw_structured_outputs: JSON.stringify(structuredOutputs),
    raw_analysis: JSON.stringify(json.analysis || {})
  }
}];

